namespace TestProject
{
    public class Program
    {
        public static void Main(string[] args)
        {
            var builder = WebApplication.CreateBuilder(args);

            // Add services to the container.

            builder.Services.AddControllers();

            // Bind the FileService configuration section and register the
            // path-safe IFileService implementation so controllers can be
            // activated through dependency injection.
            builder.Services.Configure<TestProject.Configuration.FileServiceOptions>(
                builder.Configuration.GetSection(TestProject.Configuration.FileServiceOptions.SectionName));
            builder.Services.AddSingleton<TestProject.Services.IFileService, TestProject.Services.FileService>();

            var app = builder.Build();

            // Configure the HTTP request pipeline.

            app.UseHttpsRedirection();

            app.UseDefaultFiles();

            app.UseStaticFiles();

            app.MapControllers();

            app.MapFallbackToFile("index.html");

            app.Run();
        }
    }
}

using Microsoft.AspNetCore.Http;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Provides path-safe file system operations confined to a configurable
/// home directory. All relative paths are validated so they cannot escape
/// the sandboxed root before any disk access occurs.
/// </summary>
public interface IFileService
{
    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="relativePath"/>,
    /// returning directories first (then files), each sorted by name.
    /// </summary>
    BrowseResultDto Browse(string relativePath);

    /// <summary>
    /// Recursively searches under <paramref name="relativePath"/> for entries
    /// whose name contains <paramref name="query"/> (case-insensitive).
    /// </summary>
    SearchResultDto Search(string query, string relativePath);

    /// <summary>
    /// Resolves a relative path to its absolute, normalized counterpart within
    /// the home root. Used by controllers to stream downloads.
    /// </summary>
    string ResolveFullPath(string relativePath);

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="relativeDirPath"/>, creating it if necessary, and
    /// returns the stored file's normalized relative path (the home root
    /// becomes the empty string). The returned path reflects the sanitized
    /// file name actually written to disk.
    /// </summary>
    Task<string> UploadAsync(string relativeDirPath, IFormFile file);

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="relativePath"/>.
    /// </summary>
    void Delete(string relativePath);

    /// <summary>
    /// Moves the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Move(MoveRequest request);

    /// <summary>
    /// Copies the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Copy(CopyRequest request);

    /// <summary>
    /// Creates the directory at <paramref name="relativePath"/> (including any
    /// missing parent directories), confined to the home root. Idempotent: a
    /// path that already exists as a directory is a no-op.
    /// </summary>
    void CreateDirectory(string relativePath);
}
namespace TestProject.Models;

/// <summary>
/// Represents a request to copy a file or directory from one location to another.
/// </summary>
public sealed record CopyRequest(string SourcePath, string DestinationPath);
namespace TestProject.Models;

/// <summary>
/// Represents a request to move a file or directory from one location to another.
/// </summary>
public sealed record MoveRequest(string SourcePath, string DestinationPath);

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using TestProject.Models;
using TestProject.Services;

namespace TestProject.Controllers;

/// <summary>
/// HTTP API surface for the path-safe file system operations exposed by
/// <see cref="IFileService"/>. Every endpoint is rooted under
/// <c>/api/files</c> and delegates its work to <see cref="Execute"/> (or
/// <see cref="ExecuteAsync"/> for the async <see cref="Upload"/> endpoint),
/// which translates the well-known file system faults
/// (<see cref="ArgumentException"/>, <see cref="UnauthorizedAccessException"/>
/// and <see cref="IOException"/>) into a <c>400 Bad Request</c> carrying the
/// exception message, leaving any other exception type to propagate.
/// </summary>
[ApiController]
[Route("api/[controller]")]
public class FilesController : ControllerBase
{
    private readonly IFileService _service;
    private static readonly FileExtensionContentTypeProvider ContentTypeProvider = new();

    /// <summary>Fallback MIME type used when the file extension cannot be resolved.</summary>
    private const string DefaultContentType = "application/octet-stream";

    /// <summary>
    /// Creates a new <see cref="FilesController"/> bound to the supplied
    /// <paramref name="service"/>.
    /// </summary>
    public FilesController(IFileService service)
    {
        _service = service;
    }

    // =====================================================================
    // Browse
    // =====================================================================

    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="path"/>
    /// (the root when omitted or empty), returning directories first then
    /// files, each group sorted by name.
    /// </summary>
    [HttpGet("browse")]
    public ActionResult<BrowseResultDto> Browse([FromQuery] string? path)
        => Execute(() => Ok(_service.Browse(path ?? string.Empty)));

    // =====================================================================
    // Search
    // =====================================================================

    /// <summary>
    /// Recursively searches under <paramref name="path"/> (the root when
    /// omitted or empty) for entries whose name contains <paramref name="query"/>
    /// (case-insensitive).
    /// </summary>
    [HttpGet("search")]
    public ActionResult<SearchResultDto> Search([FromQuery] string query, [FromQuery] string? path)
        => Execute(() => Ok(_service.Search(query ?? string.Empty, path ?? string.Empty)));

    // =====================================================================
    // Upload
    // =====================================================================

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="path"/> (the root when omitted or empty), creating it
    /// if necessary. The response reports the stored file's normalized
    /// relative path, sourced directly from the service.
    /// </summary>
    [HttpPost("upload")]
    public async Task<IActionResult> Upload([FromQuery] string? path, [FromForm] IFormFile file)
        => await ExecuteAsync(async () =>
        {
            var storedPath = await _service.UploadAsync(path ?? string.Empty, file);
            return Ok(new { path = storedPath });
        });

    // =====================================================================
    // Download
    // =====================================================================

    /// <summary>
    /// Streams the file at <paramref name="path"/> as a physical file
    /// response, deriving the content type from the extension (defaulting to
    /// <see cref="DefaultContentType"/> when unknown).
    /// </summary>
    [HttpGet("download")]
    public IActionResult Download([FromQuery] string path)
        => Execute(() =>
        {
            var full = _service.ResolveFullPath(path);
            var contentType = ContentTypeProvider.TryGetContentType(full, out var ct)
                ? ct
                : DefaultContentType;
            return PhysicalFile(full, contentType, Path.GetFileName(full));
        });

    // =====================================================================
    // Delete
    // =====================================================================

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="path"/>.
    /// </summary>
    [HttpDelete("delete")]
    public IActionResult Delete([FromQuery] string path)
        => Execute(() =>
        {
            _service.Delete(path);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Move
    // =====================================================================

    /// <summary>
    /// Moves the file or directory at <paramref name="request"/>'s
    /// <see cref="MoveRequest.SourcePath"/> to its
    /// <see cref="MoveRequest.DestinationPath"/>.
    /// </summary>
    [HttpPost("move")]
    public IActionResult Move([FromBody] MoveRequest request)
        => Execute(() =>
        {
            _service.Move(request);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Copy
    // =====================================================================

    /// <summary>
    /// Copies the file or directory at <paramref name="request"/>'s
    /// <see cref="CopyRequest.SourcePath"/> to its
    /// <see cref="CopyRequest.DestinationPath"/>.
    /// </summary>
    [HttpPost("copy")]
    public IActionResult Copy([FromBody] CopyRequest request)
        => Execute(() =>
        {
            _service.Copy(request);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Create directory
    // =====================================================================

    /// <summary>
    /// Creates the directory at <paramref name="path"/> (including any missing
    /// parents), creating the home root itself when omitted or empty. The
    /// operation is idempotent: an existing directory is left as-is.
    /// </summary>
    [HttpPost("mkdir")]
    public IActionResult CreateDirectory([FromQuery] string? path)
        => Execute(() =>
        {
            _service.CreateDirectory(path ?? string.Empty);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Helpers
    // =====================================================================

    /// <summary>
    /// Runs <paramref name="body"/> and translates the well-known file system
    /// faults via <see cref="TranslateException"/> into a
    /// <c>400 Bad Request</c> carrying the exception message. Any other
    /// exception type propagates unchanged.
    /// </summary>
    /// <remarks>
    /// The return type is <see cref="ActionResult"/> (rather than
    /// <see cref="IActionResult"/>) so the same helper can back both the
    /// <see cref="Browse"/>/<see cref="Search"/> endpoints, whose return type
    /// is <c>ActionResult&lt;T&gt;</c>, and the plain
    /// <see cref="IActionResult"/> endpoints; <see cref="ActionResult"/>
    /// implements <see cref="IActionResult"/> and converts implicitly to
    /// <c>ActionResult&lt;T&gt;</c>, while <see cref="IActionResult"/> does not.
    /// </remarks>
    private ActionResult Execute(Func<ActionResult> body)
    {
        try
        {
            return body();
        }
        catch (Exception ex)
        {
            return TranslateException(ex);
        }
    }

    /// <summary>
    /// Async variant of <see cref="Execute"/> for endpoints that must await
    /// service calls (currently <see cref="Upload"/>). Shares the same
    /// <see cref="TranslateException"/> translation; non-translated exceptions
    /// propagate. The body is awaited (never unwrapped via
    /// <c>.Result</c>/<c>.Wait()</c>) so a faulting body surfaces its original
    /// exception rather than an <see cref="AggregateException"/>.
    /// </summary>
    private async Task<ActionResult> ExecuteAsync(Func<Task<ActionResult>> body)
    {
        try
        {
            return await body();
        }
        catch (Exception ex)
        {
            return TranslateException(ex);
        }
    }

    /// <summary>
    /// Translates the well-known file system faults —
    /// <see cref="ArgumentException"/>, <see cref="UnauthorizedAccessException"/>
    /// and <see cref="IOException"/> — into a <c>400 Bad Request</c> carrying
    /// the exception message. The branch matching is by inheritance (is-a),
    /// so <see cref="DirectoryNotFoundException"/> and
    /// <see cref="FileNotFoundException"/> (both <see cref="IOException"/>
    /// subtypes) are handled by the single <see cref="IOException"/> branch
    /// without needing to be enumerated explicitly. Any exception that is not
    /// assignable to one of these three roots is re-thrown unchanged so it can
    /// propagate to the caller.
    /// </summary>
    /// <remarks>
    /// Shared by <see cref="Execute"/> and <see cref="ExecuteAsync"/> so the
    /// sync and async endpoints translate exceptions identically.
    /// </remarks>
    private ActionResult TranslateException(Exception ex) => ex switch
    {
        ArgumentException or UnauthorizedAccessException or IOException
            => BadRequest(new { error = ex.Message }),
        _ => throw ex
    };

}

using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Recursive name-based search over the home directory tree. Traversal is a
/// stack-based depth-first walk that matches entry names case-insensitively,
/// caps the result list at <see cref="MaxSearchResults"/>, and never descends
/// into reparse points (symbolic links / junctions): such a link may target a
/// location outside the home sandbox, and following it would let search
/// enumerate content beyond the root. The link itself remains eligible to
/// appear as a match.
/// </summary>
internal sealed class FileSearch
{
    /// <summary>
    /// Maximum number of entries a single search may return. The traversal
    /// stops as soon as this many matches have accumulated.
    /// </summary>
    private const int MaxSearchResults = 500;

    private readonly HomeRoot _root;

    /// <summary>
    /// Binds the searcher to the <see cref="HomeRoot"/> used to resolve and
    /// normalize paths. The root is not accessed at construction time, so
    /// building the searcher has no filesystem side effects.
    /// </summary>
    public FileSearch(HomeRoot root)
    {
        _root = root;
    }

    /// <summary>
    /// Recursively searches under <paramref name="relativePath"/> for entries
    /// whose name contains <paramref name="query"/> (case-insensitive), capped
    /// at <see cref="MaxSearchResults"/> matches.
    /// </summary>
    public SearchResultDto Search(string query, string relativePath)
    {
        var full = _root.SafeResolve(relativePath);
        var relative = _root.ToRelative(full);

        var results = new List<FileEntryDto>(MaxSearchResults);

        var stack = new Stack<string>();
        stack.Push(full);

        while (stack.Count > 0 && results.Count < MaxSearchResults)
        {
            var current = stack.Pop();

            // EnumerateDirectory appends this directory's matches (honoring the
            // remaining capacity) and returns the subdirectories still safe to
            // descend into. The cap is enforced inside the helper so the
            // caller never exceeds MaxSearchResults.
            var remainingCapacity = MaxSearchResults - results.Count;
            var (matches, descendInto) = EnumerateDirectory(current, query, remainingCapacity);
            results.AddRange(matches);

            foreach (var dir in descendInto)
            {
                stack.Push(dir);
            }
        }

        return new SearchResultDto(query, relative, results);
    }

    /// <summary>
    /// Enumerates a single directory, collecting the entries whose names match
    /// <paramref name="query"/> and the subdirectories that should be descended
    /// into. The match list is capped at <paramref name="remainingCapacity"/>
    /// (the number of slots left before <see cref="MaxSearchResults"/> is
    /// reached) so the caller can append it directly. Subdirectories that are
    /// reparse points are still reported as matches when their name fits the
    /// query, but are never returned for descent. An inaccessible directory
    /// (access denied, or removed between selection and enumeration) yields no
    /// matches and no descents rather than aborting the whole search.
    /// </summary>
    private (List<FileEntryDto> Matches, List<string> DescendInto) EnumerateDirectory(
        string current, string query, int remainingCapacity)
    {
        var matches = new List<FileEntryDto>();
        var descendInto = new List<string>();

        string[] subdirectories;
        string[] files;
        try
        {
            subdirectories = Directory.GetDirectories(current);
            files = Directory.GetFiles(current);
        }
        catch (UnauthorizedAccessException)
        {
            return (matches, descendInto);
        }
        catch (DirectoryNotFoundException)
        {
            return (matches, descendInto);
        }

        foreach (var dir in subdirectories)
        {
            if (matches.Count >= remainingCapacity)
            {
                break;
            }

            var info = new DirectoryInfo(dir);
            if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
            {
                matches.Add(FileSystemHelpers.BuildEntry(info, _root));
            }

            // Do not descend into reparse points (symbolic links on
            // Linux/macOS, directory junctions/symlinks on Windows): they may
            // target a location outside the home sandbox, and following them
            // would let search enumerate content beyond the root. The link is
            // still eligible to appear as a match above.
            if (!FileSystemHelpers.IsReparsePoint(info))
            {
                descendInto.Add(dir);
            }
        }

        foreach (var file in files)
        {
            if (matches.Count >= remainingCapacity)
            {
                break;
            }

            var info = new FileInfo(file);
            if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
            {
                matches.Add(FileSystemHelpers.BuildEntry(info, _root));
            }
        }

        return (matches, descendInto);
    }
}
namespace TestProject.Services;

/// <summary>
/// Validates and sanitizes untrusted uploaded file names so that any name
/// accepted on Linux is guaranteed to be acceptable on Windows too. Leading
/// directory components are stripped (closing the cross-platform
/// path-traversal gap — a backslash is a separator on Windows but a literal
/// character on Linux), and the resulting segment is rejected when it is
/// empty, contains a character illegal on Windows, or matches a reserved
/// Windows device name.
/// </summary>
internal static class FileNameSanitizer
{
    /// <summary>
    /// Characters disallowed in a stored file name on any supported platform.
    /// This is the union of <see cref="Path.GetInvalidFileNameChars"/> (which
    /// is platform-specific — on Linux it returns only NUL and '/') with the
    /// Windows-only separators and metacharacters, so a name accepted on Linux
    /// is guaranteed to be acceptable on Windows too. Without this, an upload
    /// like <c>report:2024.txt</c> succeeds on Linux but throws on Windows.
    /// </summary>
    private static readonly char[] s_invalidFileNameChars = Path.GetInvalidFileNameChars()
        .Concat(new[] { '\\', '/', ':', '*', '?', '"', '<', '>', '|' })
        .Distinct()
        .ToArray();

    /// <summary>
    /// File-name stems that Windows reserves regardless of extension (e.g.
    /// <c>CON.txt</c> is reserved just like <c>CON</c>). Rejected on every
    /// platform so an upload accepted on Linux cannot fail on Windows.
    /// </summary>
    private static readonly HashSet<string> s_reservedWindowsDeviceNames = new(StringComparer.OrdinalIgnoreCase)
    {
        "CON", "PRN", "AUX", "NUL",
        "COM1", "COM2", "COM3", "COM4", "COM5", "COM6", "COM7", "COM8", "COM9",
        "LPT1", "LPT2", "LPT3", "LPT4", "LPT5", "LPT6", "LPT7", "LPT8", "LPT9",
    };

    /// <summary>
    /// Reduces an untrusted uploaded file name to its final, safe segment and
    /// validates it. Leading directory components are stripped by treating
    /// both '/' and '\' as separators, and the resulting name is rejected when
    /// it is empty, contains a character invalid on Windows, or matches a
    /// reserved Windows device name. The returned name contains no separators
    /// and is therefore safe to combine with an already-sandboxed directory.
    /// </summary>
    public static string PrepareUploadedFileName(string? rawFileName)
    {
        var segment = (rawFileName ?? string.Empty)
            .Replace('\\', '/')
            .Split('/')
            .LastOrDefault(s => s.Length > 0 && s != "." && s != "..")
            ?? string.Empty;

        // Trim surrounding whitespace. Windows strips leading/trailing spaces
        // (and dots) from file names at the filesystem layer, so a name that is
        // only whitespace cannot exist there; trimming everywhere keeps Linux
        // consistent and reduces a whitespace-only name to the empty string,
        // which is rejected below.
        segment = segment.Trim();

        if (segment.Length == 0)
        {
            throw new ArgumentException("Invalid file name");
        }

        if (segment.IndexOfAny(s_invalidFileNameChars) >= 0)
        {
            throw new ArgumentException("File name contains invalid characters");
        }

        // Windows reserves device names like "CON" even with an extension
        // ("CON.txt"), so test the stem before the first dot.
        var dot = segment.IndexOf('.');
        var stem = dot < 0 ? segment : segment[..dot];
        if (s_reservedWindowsDeviceNames.Contains(stem))
        {
            throw new ArgumentException("File name is reserved");
        }

        return segment;
    }
}

namespace TestProject.Services;

/// <summary>
/// Recursion-bounded directory tree copying. Existing files are never
/// overwritten (matching the no-overwrite contract of
/// <see cref="File.Copy(string, string, bool)"/>), and reparse points
/// (symbolic links / junctions) are skipped rather than followed, so external
/// content is never pulled into a copy. The recursion depth is capped to
/// prevent stack overflow on pathological or self-referential trees.
/// </summary>
internal static class DirectoryCopy
{
    /// <summary>
    /// Maximum recursion depth permitted for <see cref="CopyDirectory"/>. A
    /// copy that recurses this many levels deep is treated as a pathological or
    /// self-referential tree and aborted with <see cref="IOException"/> to
    /// guard against stack overflow.
    /// </summary>
    private const int MaxCopyDepth = 32;

    /// <summary>
    /// Recursively copies a directory tree, preserving structure. Existing
    /// files are not overwritten. The recursion is bounded by
    /// <see cref="MaxCopyDepth"/>: each nested directory increments
    /// <paramref name="depth"/> by one, and once it reaches the limit the copy
    /// is aborted with <see cref="IOException"/> to prevent stack overflow on
    /// pathological or self-referential trees. Reparse points among the source
    /// files and subdirectories are skipped: a link may target a location
    /// outside the home sandbox, and following it would copy content from
    /// beyond the root. Such entries are not reproduced in the destination.
    /// </summary>
    /// <param name="source">Absolute path to the directory to copy from.</param>
    /// <param name="destination">Absolute path to the directory to copy into.</param>
    /// <param name="depth">Current recursion depth, seeded at zero by the
    /// caller that initiates a copy.</param>
    public static void CopyDirectory(string source, string destination, int depth)
    {
        if (depth >= MaxCopyDepth)
        {
            throw new IOException("Directory copy depth limit exceeded (possible cycle)");
        }

        Directory.CreateDirectory(destination);

        foreach (var file in Directory.GetFiles(source))
        {
            // Skip reparse points (e.g. symlinked files): File.Copy follows
            // the link and would copy the target's contents, which may live
            // outside the home sandbox. Such entries are not reproduced.
            if (FileSystemHelpers.IsReparsePoint(new FileInfo(file)))
            {
                continue;
            }

            File.Copy(file, Path.Combine(destination, Path.GetFileName(file)), overwrite: false);
        }

        foreach (var directory in Directory.GetDirectories(source))
        {
            // Skip reparse points (symbolic links / junctions to
            // directories): recursing into them would follow the link and copy
            // content from outside the home sandbox. The link entry itself is
            // not reproduced in the destination.
            if (FileSystemHelpers.IsReparsePoint(new DirectoryInfo(directory)))
            {
                continue;
            }

            CopyDirectory(directory, Path.Combine(destination, Path.GetFileName(directory)), depth + 1);
        }
    }
}
using Microsoft.AspNetCore.Hosting;
using TestProject.Configuration;

namespace TestProject.Services;

/// <summary>
/// Encapsulates the home-directory root and the path-sandboxing logic that
/// confines every file-system operation to it. The root path is computed at
/// construction time, but the directory itself is created lazily on first
/// access of <see cref="Root"/> so that disk I/O (and any failure it might
/// raise) is decoupled from DI resolution: a misconfigured path surfaces on
/// the first request rather than at startup. Any relative path that
/// normalizes to a location outside the home root causes an
/// <see cref="ArgumentException"/> to be thrown before any disk access.
/// </summary>
internal sealed class HomeRoot
{
    private readonly Lazy<string> _rootLazy;

    /// <summary>
    /// Captures the resolved-path computation without executing it. Creating
    /// the directory (and surfacing any I/O failure) is deferred to first use
    /// via the <see cref="Lazy{T}"/>, which is constructed with
    /// <see cref="LazyThreadSafetyMode.ExecutionAndPublication"/> so the
    /// directory is materialized exactly once even under concurrent
    /// first-access.
    /// </summary>
    public HomeRoot(IWebHostEnvironment env, FileServiceOptions options)
    {
        _rootLazy = new Lazy<string>(
            () =>
            {
                var root = Path.GetFullPath(Path.Combine(
                    env.ContentRootPath,
                    options.HomeDirectory ?? "Home"));
                Directory.CreateDirectory(root);
                return root;
            },
            LazyThreadSafetyMode.ExecutionAndPublication);
    }

    /// <summary>
    /// The resolved home root, materializing it (creating the directory on
    /// disk) on first access.
    /// </summary>
    public string Root => _rootLazy.Value;

    /// <summary>
    /// Combines the home root with <paramref name="relativePath"/>, normalizes
    /// the result, and verifies it stays within the root. A null, empty, or
    /// whitespace path resolves to the root itself. Anything that escapes the
    /// root throws <see cref="ArgumentException"/>.
    /// </summary>
    public string SafeResolve(string relativePath)
    {
        var root = Root;

        if (string.IsNullOrWhiteSpace(relativePath))
        {
            return root;
        }

        var full = Path.GetFullPath(Path.Combine(root, relativePath));

        var isRoot = string.Equals(full, root, StringComparison.Ordinal);
        var isInsideRoot = full.StartsWith(root + Path.DirectorySeparatorChar, StringComparison.Ordinal);

        if (!isRoot && !isInsideRoot)
        {
            throw new ArgumentException("Invalid path");
        }

        return full;
    }

    /// <summary>
    /// Converts an absolute path inside the root to a forward-slash relative
    /// path. The root itself becomes the empty string.
    /// </summary>
    public string ToRelative(string full)
    {
        var root = Root;
        return full
            .Substring(root.Length)
            .TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar)
            .Replace('\\', '/');
    }

    /// <summary>
    /// Computes the normalized (forward-slash) parent of a relative path.
    /// Returns <c>null</c> when <paramref name="relative"/> is the root (empty),
    /// or the empty string when the path is a direct child of the root.
    /// </summary>
    public static string? ComputeParent(string relative)
    {
        if (string.IsNullOrEmpty(relative))
        {
            return null;
        }

        return Path.GetDirectoryName(relative)?.Replace('\\', '/') ?? string.Empty;
    }
}

/**
 * Shared services for the file-browser app modules.
 *
 * The file-browser is split across several focused modules (menus, rows,
 * breadcrumb, icons, tables — re-exported as a group via the dom-builders
 * barrel — plus render-browse, render-search, toolbar-handlers, and
 * render-orchestrator). They all need access to three cross-cutting things
 * that `startApp` establishes once per mount:
 *
 *   - the {@link ApiClient} singleton (used for fetches and download URLs);
 *   - the DOM element refs the render helpers write into (results, status,
 *     breadcrumb, search input);
 *   - a "render hook" that action-button handlers and the upload handler call
 *     to trigger a fresh route dispatch (used instead of importing the
 *     orchestrator directly, which would create a module cycle: orchestrator →
 *     render-browse → rows → menus → icons → context → orchestrator).
 *
 * Centralizing them here keeps the cross-module dependency graph acyclic and
 * makes the re-bind-on-remount contract explicit: the module-level element
 * refs are rebound by `render-orchestrator.init` on every mount, so the
 * render helpers always target the most recently mounted app.
 */
import { ApiClient } from '../api.js';
import type { MenuState } from './menus.js';

/** The DOM element refs established by each `startApp` mount. */
export interface DomRefs {
  results: HTMLElement;
  status: HTMLElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
}

/* -------------------------------------------------------------------------
 * API singleton
 *
 * Created once at module load. The constructor performs
 * no I/O, so creating it before `fetch` is stubbed in a test is safe.
 * ---------------------------------------------------------------------- */
const api = new ApiClient();

/** The shared API client (used for fetches and download-URL construction). */
export function getApi(): ApiClient {
  return api;
}

/* -------------------------------------------------------------------------
 * DOM refs — rebound by `render-orchestrator.init` on every `startApp` mount
 * so `renderBrowse` / `renderSearch` always target the most recent mount.
 *
 * The definite-assignment assertions guarantee the refs are uninitialized only
 * until the first `init()` call, which always runs before any render helper
 * reads them.
 * ---------------------------------------------------------------------- */
let results!: HTMLElement;
let status!: HTMLElement;
let breadcrumb!: HTMLElement;
let searchInput!: HTMLInputElement;

/** Bind the DOM refs for the current mount. Called from the orchestrator's `init`. */
export function setRefs(refs: DomRefs): void {
  results = refs.results;
  status = refs.status;
  breadcrumb = refs.breadcrumb;
  searchInput = refs.searchInput;
}

export function getResults(): HTMLElement {
  return results;
}

export function getStatus(): HTMLElement {
  return status;
}

export function getBreadcrumb(): HTMLElement {
  return breadcrumb;
}

export function getSearchInput(): HTMLInputElement {
  return searchInput;
}

/* -------------------------------------------------------------------------
 * Menu state — rebound by `render-orchestrator.init` on every `startApp` mount
 *
 * The per-mount menu open/close state (created by `createMenuState` in
 * menus.js) so the row/directory menu single-open invariant is scoped to the
 * current mount, not a module-level singleton that would cross-contaminate
 * re-mounts. The `MenuState` type is imported TYPE-ONLY here (erased at build
 * time) so this does not introduce a runtime cycle with menus.js / icons.js,
 * which import these accessors at runtime.
 * ---------------------------------------------------------------------- */
let menuState!: MenuState;

/** Bind the per-mount menu state. Called from the orchestrator's `init`. */
export function setMenuState(state: MenuState): void {
  menuState = state;
}

/** The per-mount menu open/close state (row + directory menus). */
export function getMenuState(): MenuState {
  return menuState;
}

/* -------------------------------------------------------------------------
 * Render hook
 *
 * Action-button handlers (the menu items built in menus.js via the
 * action-button wrapper in icons.js) and the upload handler (in
 * toolbar-handlers) call `rerender()` to trigger a fresh route dispatch. They
 * cannot import `render` from render-orchestrator.ts directly without creating
 * the cycle noted above, so the orchestrator registers its `render` function
 * here during `init` and the callers invoke it indirectly through `rerender`.
 * ---------------------------------------------------------------------- */
let renderHook: () => Promise<void> = async () => {};

/** Register the route-dispatching render function. */
export function setRenderHook(fn: () => Promise<void>): void {
  renderHook = fn;
}

/** Trigger a fresh render via the registered hook. No-op until `setRenderHook` is called. */
export function rerender(): Promise<void> {
  return renderHook();
}
/**
 * Bootstrap Icons glyph and action-button builders.
 *
 * `makeIcon` produces the empty `<i class="bi bi-<name>">` element whose glyph
 * is painted by the bootstrap-icons stylesheet's `::before` pseudo-element, and
 * `makeActionButton` produces the `<button class="btn">` used by every menu
 * item (the row ⋮ menu, the right-click row menu, and the directory context
 * menu). Both insert user-controlled text via element creation / text nodes —
 * never `innerHTML` — to prevent HTML injection.
 */
import { getStatus } from './context.js';

/**
 * Build a Bootstrap Icons glyph element: an empty `<i class="bi bi-<name>">`.
 * The glyph itself is painted by the bootstrap-icons stylesheet's `::before`
 * pseudo-element (content set in CSS), so the element has NO text content of
 * its own — which keeps `textContent` assertions on the parent (e.g. a menu
 * item whose visible label is "Download") unchanged.
 */
export function makeIcon(name: string): HTMLElement {
  const icon = document.createElement('i');
  icon.className = 'bi bi-' + name;
  return icon;
}

/**
 * Build a `<button class="btn">` with the given label and click handler, and an
 * optional leading Bootstrap Icons glyph.
 *
 * The handler is wrapped so that any synchronous throw or promise rejection
 * surfaces the error via the status footer — consistent with how `render()`
 * already displays fetch errors. On normal resolution no error message is
 * shown.
 *
 * When `icon` is given it is prepended as `makeIcon(icon)` (an empty `<i>`),
 * followed by the label as a bare text node — so the button's `textContent`
 * remains exactly `label` and its `className` stays exactly `"btn"`.
 */
export function makeActionButton(
  label: string,
  handler: () => void,
  icon?: string,
): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  if (icon) {
    btn.append(makeIcon(icon));
  }
  btn.append(label);
  btn.addEventListener('click', () => {
    try {
      Promise.resolve(handler()).catch((err: unknown) => {
        getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
      });
    } catch (err) {
      getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
    }
  });
  return btn;
}

/**
 * Render a {@link SearchResult} into the shared results/breadcrumb/status
 * elements: a four-column table (Name | Path | Size | Modified).
 *
 * Operates against the DOM context established by `startApp` (via
 * `render-orchestrator.init`), so it always targets the most recently mounted
 * app.
 */
import type { SearchResult } from '../api.js';
import { renderBreadcrumb } from './breadcrumb.js';
import { getResults, getStatus } from './context.js';
import { makeSearchRow } from './rows.js';
import { buildTable } from './tables.js';

export function renderSearch(result: SearchResult): void {
  // Breadcrumb reflects the search-scope path.
  renderBreadcrumb(result.path);

  // Status footer: 'R results for "q"'
  getStatus().textContent = result.results.length + ' results for "' + result.query + '"';

  // Results table
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Path', 'Size', 'Modified']);
  const tbody = table.querySelector('tbody')!;

  for (const entry of result.results) {
    tbody.append(makeSearchRow(entry));
  }

  resultsEl.append(table);
}
export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
  /** Immediate-child count (files + folders) for directories; 0 for files. */
  itemCount?: number;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(`${this.baseUrl}/browse?path=${encodeURIComponent(path)}`, {
      method: 'GET',
    });
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' },
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData },
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/delete?path=${encodeURIComponent(path)}`, {
      method: 'DELETE',
    });
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/move`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
    });
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/copy`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
    });
  }

  async createDirectory(path: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/mkdir?path=${encodeURIComponent(path)}`, {
      method: 'POST',
    });
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + (await res.text()));
    }
    return (await res.json()) as T;
  }
}
/**
 * Pure formatting helpers for the file browser UI.
 *
 * Every function in this module is side-effect free (no DOM access, no network)
 * so each can be unit-tested in isolation. The module exports ONLY the four
 * functions declared here.
 */

/** Binary (1024-based) byte-unit suffixes, from bytes up to terabytes. */
const BYTE_UNITS = ['B', 'KB', 'MB', 'GB', 'TB'] as const;

/**
 * Format a byte count as a human-readable string using binary (1024-based)
 * units.
 *
 * - Values below 1024 render as an integer byte count, e.g. `0 B`, `1023 B`.
 * - Values of 1024 and above render with exactly one decimal place, keeping a
 *   trailing `.0`, e.g. `1.0 KB`, `1.5 KB`, `1.0 MB`.
 *
 * The unit caps at `TB`; values beyond 1024 TB remain expressed in terabytes.
 */
export function formatBytes(bytes: number): string {
  const units = BYTE_UNITS;
  let value = bytes;
  let unitIndex = 0;

  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex++;
  }

  if (unitIndex === 0) {
    // Below the KB boundary: render as an integer byte count.
    return `${Math.round(value)} ${units[unitIndex]}`;
  }

  // KB and above: one decimal place (trailing .0 preserved per spec).
  return `${value.toFixed(1)} ${units[unitIndex]}`;
}

/**
 * Normalize a relative path into a clean, slash-joined form.
 *
 * - backslashes (`\`) become forward slashes
 * - leading/trailing slashes are trimmed
 * - runs of repeated slashes collapse to one
 * - `.` and `..` segments are dropped (filtered out, NOT resolved against the
 *   parent — this also neutralizes path-traversal segments)
 * - empty/root input collapses to `""`
 */
export function normalizeRelativePath(path: string): string {
  return path
    .replace(/\\/g, '/')
    .split('/')
    .filter((segment) => segment !== '' && segment !== '.' && segment !== '..')
    .join('/');
}

/**
 * Join two path fragments with a single separating slash, then normalize the
 * result (see {@link normalizeRelativePath}).
 */
export function joinPath(base: string, name: string): string {
  return normalizeRelativePath(`${base}/${name}`);
}

/** Left-pad a number to two digits with a leading zero. */
function padTwo(value: number): string {
  return String(value).padStart(2, '0');
}

/**
 * Format an ISO 8601 date string as `yyyy-MM-dd HH:mm` (local calendar time).
 *
 * Returns `""` for empty or unparseable input instead of throwing.
 */
export function formatDate(iso: string): string {
  if (!iso) {
    return '';
  }

  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) {
    return '';
  }

  const year = date.getFullYear();
  const month = padTwo(date.getMonth() + 1);
  const day = padTwo(date.getDate());
  const hours = padTwo(date.getHours());
  const minutes = padTwo(date.getMinutes());

  return `${year}-${month}-${day} ${hours}:${minutes}`;
}

/**
 * Route dispatcher and rendering-lifecycle owner.
 *
 * `render` reads the current route, fetches the matching result from the API,
 * and delegates to `renderBrowse` / `renderSearch`. It guards against render
 * races (a slower, superseded fetch cannot clobber fresher results) via a
 * monotonic token checked after each `await`.
 *
 * `init` is called once per `startApp` mount: it binds the freshly-built DOM
 * refs into the shared context, registers `render` as the re-render hook (so
 * action buttons and uploads can trigger it without a circular import), tears
 * down any previous mount's hashchange listener, subscribes a new one, and
 * kicks off the initial render.
 */
import { getCurrentRoute, subscribe } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import {
  getApi,
  getResults,
  setMenuState,
  setRefs,
  setRenderHook,
  type DomRefs,
} from './context.js';
import { createMenuState } from './menus.js';
import { renderBrowse } from './render-browse.js';
import { renderSearch } from './render-search.js';

/** Threshold (ms) below which a search spinner is not shown.
 *  Fast searches that complete within this window avoid flashing a loading
 *  indicator; only searches that take longer display the spinner. */
const SPINNER_DELAY_MS = 500;

/* -------------------------------------------------------------------------
 * Rendering-lifecycle state
 *
 * `unsubscribe` holds the teardown for the CURRENT mount's hashchange listener.
 * `init` clears any previous listener before subscribing a new one, so a
 * re-mount never leaves the old listener on `window` (memory leak fix).
 *
 * `renderToken` is a monotonic counter incremented at the start of every
 * `render()`. Each in-flight render captures its token and, after each `await`,
 * bails out if a newer render has started — preventing a slower, superseded
 * fetch from clobbering the freshest results (render-race fix).
 * ---------------------------------------------------------------------- */
let unsubscribe: (() => void) | null = null;
let renderToken = 0;

/**
 * Bind the freshly-built DOM refs into the shared context, create a fresh
 * per-mount {@link MenuState} (so row/directory menu state never leaks across
 * mounts), register `render` as the re-render hook, tear down any previous
 * mount's hashchange listener, subscribe a new one, and kick off the initial
 * render.
 */
export function init(refs: DomRefs): void {
  setRefs(refs);
  setMenuState(createMenuState());
  setRenderHook(render);
  // Tear down the previous mount's listener first (if any) so re-mounts never
  // accumulate hashchange listeners on `window`.
  if (unsubscribe !== null) {
    unsubscribe();
    unsubscribe = null;
  }
  unsubscribe = subscribe(render);
  render();
}

/**
 * Route dispatcher.
 *
 * Clears the results container synchronously (so a pending/failed fetch never
 * leaves a stale table behind) but does NOT clear the breadcrumb or status
 * here. Clearing those synchronously would remove in-page navigation targets
 * in the middle of a click handler: `navigate()` dispatches `hashchange`
 * synchronously in happy-dom, which would re-enter `render` and wipe the
 * breadcrumb before the click's caller can read the next segment. The
 * breadcrumb/status are instead refreshed by `renderBrowse`/`renderSearch`
 * once data arrives.
 */
export async function render(): Promise<void> {
  // Claim this render slot. A newer render increments `renderToken` past
  // `myToken`; after each `await` we bail out if superseded so a slower fetch
  // can never overwrite the freshest results, breadcrumb, or status.
  const myToken = ++renderToken;
  const route = getCurrentRoute();
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  // Debounced spinner: a search fetch only shows a spinner if it is still in
  // flight after 500ms, so fast searches never flash a loading indicator. The
  // timer is cleared on every exit path (success, error, superseded), and its
  // callback also bails if a newer render has claimed the slot — so a slower,
  // superseded fetch can never re-add a stale spinner. For browse routes, no
  // spinner is ever shown. When results do render, the spinner (if shown) is
  // removed naturally: `renderSearch(result)` clears the container before
  // building the table, and the error handler's `textContent` replaces all.
  let spinnerTimer: ReturnType<typeof setTimeout> | null = null;
  const clearSpinnerTimer = (): void => {
    if (spinnerTimer !== null) {
      clearTimeout(spinnerTimer);
      spinnerTimer = null;
    }
  };
  if (route.view === 'search') {
    spinnerTimer = setTimeout(() => {
      spinnerTimer = null;
      // A newer render owns the slot — don't re-add a stale spinner.
      if (myToken !== renderToken) return;
      const spinnerWrap = document.createElement('div');
      spinnerWrap.className = 'search-spinner';
      const spinnerIcon = document.createElement('i');
      spinnerIcon.className = 'bi bi-arrow-repeat spinning';
      spinnerWrap.appendChild(spinnerIcon);
      resultsEl.appendChild(spinnerWrap);
    }, SPINNER_DELAY_MS);
  }
  try {
    if (route.view === 'browse') {
      const result = await getApi().browse(normalizeRelativePath(route.path));
      clearSpinnerTimer();
      if (myToken !== renderToken) return;
      renderBrowse(result);
    } else {
      const result = await getApi().search(route.query, normalizeRelativePath(route.path));
      clearSpinnerTimer();
      if (myToken !== renderToken) return;
      renderSearch(result);
    }
  } catch (err) {
    clearSpinnerTimer();
    // A superseded render must not even commit its error.
    if (myToken !== renderToken) return;
    // textContent replaces all children, so any stale table is removed too.
    resultsEl.textContent =
      err instanceof Error ? 'Error: ' + err.message : 'Error: ' + String(err);
  }
}

/**
 * Toolbar event handlers: search submission, search clearing, and upload into
 * an arbitrary folder (via the context-menu / row "Upload" action).
 *
 * They operate against the shared DOM/API context (search input value, current
 * route) and trigger a re-render via the context's render hook.
 */
import { getCurrentRoute, navigate, toBrowseHash, toSearchHash } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getSearchInput, getStatus, rerender } from './context.js';

/**
 * Navigate to a search hash for the current input value and browse path.
 *
 * A query of fewer than two characters (after trimming) does not search: it
 * navigates to the browse route for the current path instead, so the server
 * never receives a too-short `query`. This mirrors the empty-query fallback
 * and keeps the input's text intact (only the route changes).
 */
export function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  const query = getSearchInput().value.trim();
  if (query.length < 2) {
    navigate(toBrowseHash(path));
    return;
  }
  navigate(toSearchHash(query, path));
}

/**
 * Clear the search input and return to the browse view for the current path.
 *
 * Resets the search input value to an empty string, reads the current path
 * (normalised), and navigates to the browse hash for that path — the same
 * behaviour as {@link doSearch} when the query is too short, but exposed as an
 * explicit, unconditional entry point that also wipes the input text.
 */
export function clearSearch(): void {
  getSearchInput().value = '';
  const path = normalizeRelativePath(getCurrentRoute().path);
  navigate(toBrowseHash(path));
}

/**
 * Open the native file picker and upload every selected file into `dirPath`
 * (an arbitrary directory, NOT necessarily the current route) — used by the
 * folder-row "Upload" and the current-directory context menus.
 *
 * Uses a self-contained, transient `<input type="file" multiple>` appended
 * hidden to body, clicked (within the menu-item click's user gesture so the
 * picker is allowed to open), awaited until either `change` (files chosen) or
 * `cancel` (dismissed) settles, then removed — so a cancel resolves cleanly
 * with no upload and no leak. Because `cancel` is non-standard and not fired
 * by every browser, a `window` `focus` event (fired when the dialog closes and
 * focus returns) is also used as a fallback settle signal, deferred briefly so
 * a real `change` with chosen files wins first. Each file is uploaded in
 * order; per-file failures are collected and surfaced in the status footer
 * without aborting the rest.
 */
export async function pickAndUploadInto(dirPath: string): Promise<void> {
  const input = document.createElement('input');
  input.type = 'file';
  input.multiple = true;
  input.style.display = 'none';
  document.body.append(input);

  const files = await new Promise<File[]>((resolve) => {
    // Grace window (ms) letting a real `change` (with files) win over the
    // focus fallback so genuine selections are never swallowed.
    const FOCUS_SETTLE_DELAY_MS = 100;
    let settled = false;
    const onFocus = (): void => {
      // Defer slightly so a real `change` arriving after focus can settle
      // with the chosen files first; the `settled` guard then makes the
      // later timeout a no-op. Files are read at fire time, not schedule
      // time, so a selection made before the delay elapses is honoured.
      setTimeout(
        () => finish(input.files && input.files.length > 0 ? Array.from(input.files) : []),
        FOCUS_SETTLE_DELAY_MS,
      );

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * This module is the thin entry point: it builds the DOM imperatively, wires
 * toolbar/dialog events, binds the resulting element refs into the render
 * orchestrator (which owns the route dispatch and render lifecycle), and kicks
 * off the initial render. The rendering logic itself lives in the focused
 * modules under `./app/`:
 *
 *   - `./app/context.js`             — shared API client, DOM refs, render hook
 *   - `./app/dom-builders.js`        — table/breadcrumb/row/action-button builders
 *   - `./app/render-browse.js`       — browse-result rendering
 *   - `./app/render-search.js`       — search-result rendering
 *   - `./app/toolbar-handlers.js`    — search + upload-into-folder handlers
 *   - `./app/render-orchestrator.js` — route dispatch + render lifecycle
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + .search-wrapper (search <input> +
 *                search-icon + clear-btn)
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 *
 * `renderBrowse` and `renderSearch` are re-exported so test suites and
 * consumers can import them from the barrel module:
 * `import { startApp, renderBrowse, renderSearch } from './app'`.
 */
import { doSearch, clearSearch } from './app/toolbar-handlers.js';
import { init } from './app/render-orchestrator.js';
import type { DomRefs } from './app/context.js';

export { renderBrowse } from './app/render-browse.js';
export { renderSearch } from './app/render-search.js';

/** Delay (ms) after the last keystroke before firing a search query.
 *  Prevents pounding the API on every character while keeping the UI responsive. */
const SEARCH_DEBOUNCE_MS = 200;

/* =========================================================================
 * startApp — build the DOM, wire events, bind refs, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  const breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  // Search affordance: a wrapper holding the input, a leading search icon,
  // and a trailing clear button (the latter toggled purely by CSS via
  // `:placeholder-shown`, so it needs no ref in DomRefs).
  const searchWrapper = document.createElement('div');
  searchWrapper.className = 'search-wrapper';
  const searchIcon = document.createElement('i');
  searchIcon.className = 'bi bi-search search-icon';
  const searchClearBtn = document.createElement('button');
  searchClearBtn.className = 'clear-btn';
  searchClearBtn.type = 'button';
  searchClearBtn.setAttribute('aria-label', 'Clear search');
  const clearIcon = document.createElement('i');
  clearIcon.className = 'bi bi-x-lg';
  searchClearBtn.append(clearIcon);
  // ORDER MATTERS: input first, then icon, then clear-btn (CSS uses ~ sibling combinator)
  searchWrapper.append(searchInput, searchIcon, searchClearBtn);
  toolbar.append(breadcrumbEl, searchWrapper);

  // Results container + status footer
  const resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  const statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so the context refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  // Debounced search: re-fire `doSearch` 200ms after the last keystroke so
  // typing a query doesn't pound the API on every character.
  let searchDebounceTimer: ReturnType<typeof setTimeout> | null = null;
  searchInput.addEventListener('input', () => {
    if (searchDebounceTimer !== null) {
      clearTimeout(searchDebounceTimer);
    }
    searchDebounceTimer = setTimeout(() => {
      searchDebounceTimer = null;
      doSearch();
    }, SEARCH_DEBOUNCE_MS);
  });
  // Clear button: wipe the input and return to the browse view.
  searchClearBtn.addEventListener('click', clearSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    } else if (event.key === 'Escape') {
      // stopPropagation is critical: when the widget lives inside the open
      // <dialog>, the native ESC-to-close would otherwise dismiss the dialog.
      event.stopPropagation();
      clearSearch();
    }
  });

  /* --- Bind refs into the orchestrator + context, subscribe, and kick off
     the initial render. --- */
  const refs: DomRefs = {
    results: resultsEl,
    status: statusEl,
    breadcrumb: breadcrumbEl,
    searchInput,
  };
  init(refs);
}

